import type { ScenarioQuestion } from "./types";

function q(id: string, group: string, sub: string, scenario: string, question: string, answer: string, feedback: string, diff: "beginner" | "intermediate" | "advanced"): ScenarioQuestion {
  return { id, formatType: "scenario", categoryGroup: group, subcategory: sub, scenarioPrompt: scenario, question, exampleAnswer: answer, feedback, difficulty: diff };
}

export const expandedBatch4: ScenarioQuestion[] = [
  q("sq-ex4-1","interview_preparation","behavioral","You volunteered at a free clinic during nursing school.","How has volunteer experience shaped your nursing perspective?","Volunteering at a free clinic exposed me to healthcare disparities that textbooks cannot fully convey. I cared for patients who delayed treatment due to cost, language barriers, and mistrust of the healthcare system. This experience deepened my commitment to equitable care and taught me that understanding a patient's social context is as important as understanding their diagnosis.","Authentic connection between experience and professional values.","beginner"),
  q("sq-ex4-2","interview_preparation","clinical_judgment","A patient with a tracheostomy develops high-pitched sounds during breathing.","What does stridor in a tracheostomy patient indicate?","Stridor in a tracheostomy patient could indicate partial airway obstruction from secretions, a displaced tube, or tracheal granulation tissue. I would suction the trach immediately, assess tube position, provide supplemental oxygen, and have emergency equipment ready including a spare trach. If stridor persists after suctioning, I would notify the provider immediately for possible bronchoscopy.","Stridor assessment and management in tracheostomy patients.","advanced"),
  q("sq-ex4-3","interview_preparation","scenario_responses","A patient tells you they have been using recreational marijuana for pain management.","How would you respond to a patient disclosing recreational drug use?","I would respond non-judgmentally: 'Thank you for being honest with me. It is important for your care team to know what substances you are using so we can avoid interactions and manage your pain effectively.' I would document the use, inform the physician, and discuss evidence-based pain management alternatives. Judgment-free communication encourages honest disclosure.","Non-judgmental response encouraging continued honest disclosure.","beginner"),
  q("sq-ex4-4","workplace_scenarios","prioritization","You need to prepare two patients for surgery happening at the same time.","How would you prepare two patients for simultaneous procedures?","I would organize tasks by urgency: verify consent forms first (cannot proceed without them), then complete pre-op checklists in parallel. I would delegate vitals and preparation tasks to the CNA, coordinate timing with the OR scheduler, and ensure both patients' pre-op antibiotics are given within the required window. I would communicate timeline concerns to the charge nurse if help is needed.","Parallel processing with delegation for simultaneous deadlines.","intermediate"),
  q("sq-ex4-5","workplace_scenarios","delegation","You delegate feeding assistance to a CNA for a patient on thickened liquids.","How would you ensure safe delegation of modified diet feeding?","I would confirm the CNA knows the patient is on thickened liquids and understands the consistency level. I would remind them to position the patient upright, feed slowly, and watch for signs of aspiration like coughing or wet voice quality. I would verify the CNA has been trained on modified diet protocols and follow up after the meal to assess tolerance.","Diet modification education and aspiration risk awareness in delegation.","intermediate"),
  q("sq-ex4-6","workplace_scenarios","patient_safety","A patient on oxygen therapy wants to use a petroleum-based lip balm.","How would you address fire safety with oxygen therapy?","I would explain that petroleum-based products are combustible near oxygen and could cause a flash fire. I would provide a non-petroleum alternative lip balm. I would reinforce other oxygen safety precautions: no smoking, keep oxygen away from heat sources, and ensure electrical equipment near oxygen is properly grounded. Fire safety with oxygen therapy is critical.","Oxygen-related fire safety education.","beginner"),
  q("sq-ex4-7","workplace_scenarios","medication_error","You discover that a patient has been receiving a medication that was discontinued two days ago.","How would you handle discovering a medication that should have been discontinued?","I would stop the medication immediately, assess the patient for any adverse effects from the additional doses, and notify the provider. I would investigate why the discontinuation was not processed in the MAR—was it a communication failure, a system error, or an oversight? I would file an incident report and ensure the MAR is corrected. I would document the extra doses and patient assessment.","System investigation for medication discontinuation failures.","intermediate"),
  q("sq-ex4-8","workplace_scenarios","handoff_communication","You are giving report but the receiving nurse keeps being called away.","How would you ensure a complete handoff despite interruptions?","I would ask the charge nurse for protected time for the handoff. If interruptions continue, I would provide a written summary with key priorities and follow up to ensure the receiving nurse reviews it. I would highlight the most critical information first in case we are interrupted again. I would not leave until I am confident the receiving nurse has the essential information for safe care.","Adapting handoff strategies when standard methods are disrupted.","intermediate"),
  q("sq-ex4-9","workplace_scenarios","difficult_coworkers","A colleague repeatedly uses your supplies without replacing them.","How would you address a colleague using your supplies?","I would address it directly but casually: 'I noticed some of my supplies have been used from my patient's room. No worries, but could you grab replacements when you borrow things? I want to make sure I have what I need when I am in there.' If it continued, I would keep essential supplies secured and involve the charge nurse.","Direct, casual communication for minor but persistent annoyances.","beginner"),
  q("sq-ex4-10","workplace_scenarios","interdisciplinary_communication","A new physician joins the team and is unfamiliar with unit protocols.","How would you help orient a new physician to unit practices?","I would be welcoming and helpful: 'Welcome to the unit. Here are some of our key protocols and communication preferences. We use SBAR for phone reports, and our charge nurse is always available for questions.' I would offer to be a resource without being condescending. Helping new team members integrate smoothly improves patient care and team function.","Supportive onboarding of new interdisciplinary team members.","beginner"),
  q("sq-ex4-11","clinical_transition","first_shift","Your scrubs get soiled during your first shift.","How would you handle getting soiled at work?","I would change into clean scrubs from the hospital supply—most facilities have scrub machines or backup scrubs available. I would bag the soiled scrubs for laundering. I would continue my shift without being overly self-conscious. This is a normal part of nursing, and having a backup set of scrubs in my locker is a smart practice for future shifts.","Practical response to common nursing realities.","beginner"),
  q("sq-ex4-12","clinical_transition","new_nurse_anxiety","You feel like you will never be as good as the nurses you admire.","How would you manage comparison-based self-doubt?","I would remember that the nurses I admire were once exactly where I am. I would ask them about their early career experiences—most will share that they struggled too. I would focus on my own growth trajectory rather than comparing my beginning to their expertise. I would set specific, achievable goals and celebrate small wins. Competence is built over years, not weeks.","Growth mindset with focus on personal trajectory.","beginner"),
  q("sq-ex4-13","clinical_transition","time_management","You have a patient who requires 1:1 sitter coverage but no sitter is available.","How would you manage when 1:1 coverage is unavailable?","I would communicate the staffing gap to the charge nurse immediately. I would implement safety measures: bed alarm, frequent rounding every 15 minutes, room close to the nurses' station, and family involvement if appropriate. I would document the need for a sitter and the alternative safety measures implemented. I would advocate for appropriate staffing through the chain of command.","Safety alternatives when ideal resources are unavailable.","intermediate"),
  q("sq-ex4-14","clinical_transition","documentation_challenges","You realize your documentation from two hours ago has an error in the vital signs.","How would you correct a vital sign documentation error hours later?","I would add a late entry correcting the vital sign values with the actual time of the original measurement. I would not alter the original entry. I would note that this is a correction: 'Late entry: BP at 0800 was recorded as 120/80 but was actually 140/90.' I would assess whether the incorrect value affected any clinical decisions and notify the provider if needed.","Proper late entry correction with clinical impact assessment.","beginner"),
  q("sq-ex4-15","clinical_transition","critical_thinking_drills","A patient's creatinine has risen from 1.0 to 2.5 mg/dL over 48 hours.","What does a rapidly rising creatinine indicate?","A doubling of creatinine over 48 hours indicates acute kidney injury (AKI). I would assess fluid status, urine output, recent medications (especially nephrotoxic drugs like NSAIDs, aminoglycosides, or contrast dye), and hemodynamic status. I would notify the provider, anticipate a nephrology consult, hold any nephrotoxic medications, and ensure adequate hydration unless fluid-restricted.","Acute kidney injury recognition with medication review priority.","intermediate"),
  q("sq-ex4-16","professional_development","professional_boundaries","A patient tries to follow you on Instagram after seeing your name badge.","How would you handle a patient finding you on social media?","I would ensure my social media privacy settings prevent patients from accessing my personal content. I would not accept the follow request. If the patient mentions it, I would explain my professional boundaries kindly. I would consider using only my first name on my badge or minimizing personal information visible on social media profiles.","Proactive privacy management on social media.","beginner"),
  q("sq-ex4-17","professional_development","ethical_dilemmas","You are asked to care for a patient whose actions caused harm to someone you know.","How would you provide care to someone who harmed someone you know?","I would assess whether I can provide objective, quality care despite the personal connection. If I can maintain professionalism, I would proceed while being mindful of my emotions. If I believe my objectivity would be compromised, I would privately request a reassignment from the charge nurse. Every patient deserves quality care regardless of their history, but nurses also need to practice self-awareness.","Self-assessment of objectivity with reassignment option.","advanced"),
  q("sq-ex4-18","professional_development","workplace_bullying","Experienced nurses use inside jokes and references that exclude new staff.","How would you address subtle exclusion through cultural gatekeeping?","I would take initiative to learn unit culture and history by asking questions naturally. I would build individual relationships rather than trying to break into the group. I would organize inclusive activities and invite all team members. If the exclusion is deliberate and affects work communication, I would address it with the manager. Some cultural integration simply takes time.","Proactive integration with distinction between natural adjustment and deliberate exclusion.","beginner"),
  q("sq-ex4-19","professional_development","advocacy","A non-English speaking patient has been using a 10-year-old child as an interpreter for medical decisions.","How would you address inappropriate use of a child as a medical interpreter?","I would immediately arrange for a certified medical interpreter. Using a child to interpret medical information is inappropriate—it places an unfair burden on the child, compromises accuracy, and violates HIPAA. I would gently explain to the family: 'To make sure we communicate everything accurately and protect your child from stressful medical discussions, we will arrange a professional interpreter.'","Advocating against inappropriate interpretation practices.","intermediate"),
  q("sq-ex4-20","professional_development","patient_communication","A patient is frustrated because they have been waiting hours for test results.","How would you address patient frustration about delays?","I would validate their frustration: 'I understand the waiting is difficult, especially when you are anxious about results.' I would provide a realistic timeline if possible and explain the process: 'Lab results typically take X hours to process.' I would offer to check on the status and provide updates. I would address comfort needs while they wait. Transparency and regular updates reduce frustration.","Validation, realistic timelines, and proactive updates.","beginner"),
  q("sq-ex4-21","career_navigation","job_offer_negotiation","You want to negotiate for more PTO than what is offered.","How would you negotiate for additional paid time off?","I would frame it as part of the total compensation discussion: 'I am very interested in this position. One thing I would like to discuss is the PTO allocation. Given that work-life balance directly impacts nurse retention and patient care quality, would there be flexibility to add an additional week of PTO?' I would be prepared for alternatives like unpaid leave or a PTO advancement schedule.","PTO negotiation within total compensation framework.","intermediate"),
  q("sq-ex4-22","career_navigation","probation_period","You feel your preceptor's evaluation of you is unfairly negative.","How would you address a potentially unfair preceptor evaluation?","I would first reflect honestly—is the evaluation truly unfair, or am I being defensive about valid feedback? If I believe it is unfair, I would request a meeting with both my preceptor and my nurse educator to discuss specific examples. I would present my own evidence of competency. If the relationship is unworkable, I would request a preceptor change through proper channels rather than suffering in silence.","Honest self-reflection before challenging evaluator fairness.","intermediate"),
  q("sq-ex4-23","career_navigation","performance_evaluation","Your evaluation recommends you take on more complex patients.","How would you prepare to take on higher-acuity patients?","I would request a gradual increase in complexity with mentored support. I would study conditions I am less familiar with, review protocols for high-acuity patients, and ask to shadow experienced nurses managing complex cases. I would communicate my readiness and any concerns to my charge nurse. Progressive complexity with adequate support builds competence safely.","Graduated complexity increase with support structure.","beginner"),
  q("sq-ex4-24","career_navigation","career_advancement","You are considering earning a certification but are unsure which one is best.","How would you select the right nursing certification?","I would consider: which certification aligns with my current practice and career goals, the eligibility requirements and my ability to meet them, the exam format and study resources available, the financial investment and employer support, and the certification's recognition and value in the job market. I would talk to certified nurses in my area to understand the practical benefits.","Strategic certification selection aligned with career path.","beginner"),
  q("sq-ex4-25","interview_preparation","behavioral","Tell me about a time you had to balance quality with efficiency.","How do you maintain quality under time pressure?","During a busy clinical shift with multiple discharges, I realized I could rush through discharge teaching or take slightly longer to ensure patients truly understood their care plan. I chose to be thorough but efficient by using pre-prepared visual aids and the teach-back method, which actually saved time compared to unstructured teaching. I learned that systematic approaches can achieve both quality and speed.","Systematic approaches that achieve both quality and efficiency.","intermediate"),
  q("sq-ex4-26","interview_preparation","clinical_judgment","A patient on chemotherapy has a platelet count of 15,000.","What precautions would you take for severe thrombocytopenia?","With a platelet count of 15,000 (normal 150,000-400,000), the patient is at high risk for spontaneous bleeding. I would implement bleeding precautions: use a soft toothbrush, avoid IM injections, apply pressure to venipuncture sites for at least 10 minutes, avoid rectal temperatures or enemas, use an electric razor only, monitor for signs of bleeding, and avoid aspirin and NSAIDs. I would anticipate possible platelet transfusion.","Comprehensive bleeding precautions for thrombocytopenia.","intermediate"),
  q("sq-ex4-27","workplace_scenarios","prioritization","You receive STAT labs, a new admission, and a physician wanting to round all at the same time.","How would you handle three competing demands from different sources?","I would prioritize the STAT labs as they are often ordered for urgent clinical decisions. I would communicate with the physician about when I will be available for rounds—even 15 minutes makes a difference. I would begin the admission assessment but delegate room setup and vital signs to the CNA. I would communicate my situation to the charge nurse if I need additional support.","Transparent communication about competing priorities with all parties.","intermediate"),
  q("sq-ex4-28","workplace_scenarios","patient_safety","A patient is using a CPAP machine at night and it seems to be malfunctioning.","How would you troubleshoot a malfunctioning CPAP device?","I would check the basics: is it plugged in, is the mask properly sealed, is the tubing connected and not kinked, and is the pressure setting correct? I would assess the patient's oxygen saturation and respiratory status. If I cannot resolve the issue, I would contact respiratory therapy for assessment. I would document the malfunction and ensure the patient is monitored closely overnight without the CPAP if it cannot be fixed.","Basic troubleshooting before escalating to specialized support.","beginner"),
  q("sq-ex4-29","clinical_transition","first_shift","A patient requests a specific brand of pain medication that your hospital does not carry.","How would you handle a medication brand preference?","I would explain that hospitals use generic equivalents that contain the same active ingredient and dosage. I would reassure the patient about the effectiveness. If the patient insists due to a genuine issue like an allergy to an inactive ingredient in the available brand, I would notify the pharmacist and physician to find an alternative. Most brand preferences can be addressed through education.","Education about generic equivalents with attention to genuine ingredient concerns.","beginner"),
  q("sq-ex4-30","clinical_transition","critical_thinking_drills","A patient develops sudden unilateral leg swelling with positive Homans' sign after prolonged bed rest.","What condition do these findings suggest?","Unilateral leg swelling with calf pain on dorsiflexion (positive Homans' sign) after prolonged immobility strongly suggests deep vein thrombosis. I would not massage the leg, I would elevate it, and I would notify the provider immediately. I would anticipate a Doppler ultrasound and anticoagulation therapy. I would also assess for signs of pulmonary embolism. Sequential compression devices should be applied to the unaffected leg.","DVT recognition with appropriate interventions and PE vigilance.","intermediate"),
  q("sq-ex4-31","professional_development","ethical_dilemmas","A coworker asks you to sign off on a competency they observed you demonstrating even though they were not actually present.","How would you handle a request to falsify competency documentation?","I would decline firmly: 'I cannot sign off on something I was not present to observe. Let us schedule a time for you to actually watch me perform the skill so we can sign off properly.' Falsifying competency documentation is dishonest and dangerous—it creates a false record that could put patients at risk if the person is not actually competent.","Refusing to falsify documentation with constructive alternative.","intermediate"),
  q("sq-ex4-32","professional_development","advocacy","A patient with a disability is being spoken to in a condescending manner by a team member.","How would you address condescending communication toward a patient with a disability?","I would model appropriate communication by speaking directly to the patient at their level. I would privately speak with the team member: 'I noticed the way you communicated with Mrs. Garcia seemed a bit different from how you talk to other patients. She has a physical disability but is cognitively intact—speaking to her directly and normally is important for her dignity.' I would document and escalate if it continued.","Modeling appropriate behavior and private colleague education.","intermediate"),
  q("sq-ex4-33","career_navigation","career_advancement","You are considering becoming a nurse educator but are unsure about transitioning out of bedside care.","How would you explore nursing education without leaving bedside care?","I would start by precepting new graduates, which develops teaching skills while maintaining clinical practice. I would volunteer to lead unit-based education sessions. I would pursue a teaching certification or MSN in nursing education. Many clinical educators maintain part-time bedside practice, allowing me to combine both passions. I would shadow current nurse educators to understand the daily reality of the role.","Exploring education through precepting and part-time roles.","intermediate"),
  q("sq-ex4-34","interview_preparation","clinical_judgment","A patient with known heart failure is prescribed a high-dose NSAID for pain.","What concern does this prescription raise?","NSAIDs can cause fluid retention and worsen heart failure. They can also reduce the effectiveness of diuretics and ACE inhibitors. I would question this order by contacting the prescriber: 'I wanted to verify this NSAID order for our heart failure patient, given the potential for fluid retention and interaction with their cardiac medications. Would an alternative analgesic like acetaminophen be appropriate?' I would not administer without clarification.","Recognizing dangerous drug-disease interactions.","intermediate"),
  q("sq-ex4-35","workplace_scenarios","medication_error","A patient tells you they already took their own medication that they brought from home while you were preparing the same medication.","How would you handle a patient who self-administered medication?","I would not give the additional dose. I would assess the patient, document the self-administration, and notify the provider about the potential for a double dose. I would secure the patient's home medications to prevent future self-administration. I would educate the patient about the importance of allowing the nursing staff to manage all medications during hospitalization to prevent dangerous interactions or overdoses.","Preventing duplicate dosing and securing home medications.","intermediate"),
  q("sq-ex4-36","clinical_transition","time_management","You are running behind and a patient is upset about waiting for their pain medication.","How would you address a patient angry about delayed pain medication?","I would acknowledge their pain and apologize for the delay: 'I am sorry you have been waiting. Your comfort is important to me. Let me get your medication right now.' I would administer the medication promptly and follow up within 30 minutes to assess effectiveness. I would reevaluate my workflow to prevent future delays and consider whether a PRN pain management adjustment would help.","Empathetic response with immediate action and workflow improvement.","beginner"),
  q("sq-ex4-37","professional_development","patient_communication","A patient asks you technical questions about their surgery that you cannot answer.","How would you handle questions outside your clinical knowledge?","I would be honest: 'That is a great question about the specific surgical technique. Your surgeon is the best person to explain those details. Would you like me to arrange a time for them to speak with you?' I would write down the patient's questions to relay to the surgeon. I would answer what I can within my scope—post-operative care instructions, recovery expectations, and comfort measures.","Scope-appropriate responses with physician referral.","beginner"),
  q("sq-ex4-38","interview_preparation","behavioral","Describe your approach to continuous quality improvement.","How do you contribute to quality improvement?","I actively look for patterns in patient outcomes, near-misses, and workflow inefficiencies. When I identify an issue, I document it, propose a solution, and work with the team to implement it. For example, I noticed that patients frequently missed follow-up appointments after discharge. I proposed adding a phone reminder system and volunteered to pilot it. Quality improvement is everyone's responsibility, not just management's.","Proactive quality improvement with specific example.","intermediate"),
  q("sq-ex4-39","workplace_scenarios","interdisciplinary_communication","The social worker recommends a rehabilitation facility that you believe is not appropriate for the patient.","How would you address disagreement with a discharge recommendation?","I would share my clinical concerns with specific data: 'Based on my assessment, the patient needs 24-hour skilled nursing care, and this rehab facility provides a lower level of care than what I believe they need.' I would request a team meeting to discuss the options and ensure the patient and family are included in the decision. I would document my concerns and advocacy.","Data-driven interdisciplinary disagreement resolution.","intermediate"),
  q("sq-ex4-40","career_navigation","performance_evaluation","Your manager gives you an outstanding evaluation and asks about your career aspirations.","How would you leverage a positive evaluation for career growth?","I would use the moment to discuss specific career goals: 'I am interested in pursuing charge nurse opportunities, and I would like to work toward my specialty certification this year. Would you be willing to mentor me and support these goals?' I would follow up with a written development plan. Positive evaluations are the ideal time to advocate for advancement opportunities and support.","Using positive momentum for career advancement discussions.","beginner"),
  q("sq-ex4-41","interview_preparation","clinical_judgment","A patient recovering from abdominal surgery has no bowel sounds on assessment.","When should absent bowel sounds concern you?","Absent bowel sounds are common in the immediate post-operative period (paralytic ileus) and may not be concerning in the first 24-48 hours after abdominal surgery. However, prolonged absence beyond 72 hours, combined with abdominal distension, nausea, or vomiting, suggests a more serious ileus or potential obstruction. I would assess the abdomen thoroughly, maintain NPO status, and notify the provider if bowel function does not return within expected timeframes.","Contextual assessment of absent bowel sounds post-operatively.","intermediate"),
  q("sq-ex4-42","workplace_scenarios","patient_safety","A patient is wearing a medical alert bracelet for a condition not documented in their chart.","How would you handle discovering undocumented medical information?","I would ask the patient about the condition on their medical alert bracelet and verify the information. I would update the chart immediately—allergies, chronic conditions, and surgical history. I would notify the physician about the undocumented condition. Medical alert bracelets are worn for life-threatening conditions, so failing to document this information could be dangerous.","Proactive identification and documentation of undiscovered medical information.","beginner"),
  q("sq-ex4-43","clinical_transition","new_nurse_anxiety","You made a good catch that potentially saved a patient, but you cannot stop thinking about what would have happened if you had missed it.","How would you process a near-miss that you caught?","I would acknowledge the positive outcome—I caught the issue because my training and clinical judgment worked. I would use the experience as reinforcement of the importance of thorough assessment. I would share the learning with my team during a safety huddle. I would allow myself to feel the emotions but not let 'what if' thinking spiral into anxiety. Good catches should build confidence, not fear.","Processing near-misses as confidence builders rather than anxiety triggers.","beginner"),
  q("sq-ex4-44","professional_development","ethical_dilemmas","A wealthy patient receives noticeably more attention from staff than other patients.","How would you address inequitable care based on social status?","I would examine my own behavior first to ensure I am providing equitable care regardless of a patient's social or financial status. If I observed colleagues giving preferential treatment, I would raise it diplomatically: 'I want to make sure all our patients feel equally valued and attended to.' I would bring systemic concerns to the patient care committee without singling out individuals.","Self-examination first, then constructive systemic advocacy.","intermediate"),
  q("sq-ex4-45","career_navigation","probation_period","Your manager mentions during a casual conversation that there have been some concerns about you from other staff.","How would you respond to vague concerns mentioned informally?","I would ask for specific details in a professional setting: 'I want to take any concerns seriously. Could we schedule a formal meeting so I can understand the specific feedback and develop a plan to address it?' I would not become defensive or demand to know who said what. I would focus on understanding and addressing the underlying issues rather than the source.","Requesting formal specifics from informal feedback.","intermediate"),
  q("sq-ex4-46","interview_preparation","scenario_responses","A patient asks you what would happen if they left against medical advice.","How would you educate a patient considering leaving AMA?","I would explain clearly without being threatening: 'You have the right to leave at any time. However, I want you to understand the medical risks involved. Without completing your treatment, there is a risk of [specific complications]. Your insurance may also not cover expenses related to your AMA departure.' I would explore the reasons they want to leave and address them if possible. I would have them sign AMA paperwork and provide discharge instructions.","Informative AMA education without coercion.","intermediate"),
  q("sq-ex4-47","workplace_scenarios","delegation","You are the charge nurse and need to assign a complex admission to a team with varying experience levels.","How would you assign a complex patient to the most appropriate nurse?","I would consider each nurse's current patient load, acuity level, experience with the presenting condition, and their expressed comfort level. I would assign the complex patient to the nurse best equipped to manage them while ensuring the rest of the team has balanced assignments. I would offer support to whichever nurse receives the assignment and check in frequently.","Competency-based assignment with support structure.","intermediate"),
  q("sq-ex4-48","clinical_transition","critical_thinking_drills","A patient's aPTT is 45 seconds while on heparin (therapeutic range 60-80 seconds).","What does a subtherapeutic aPTT mean for this patient?","A subtherapeutic aPTT on heparin means the patient is not adequately anticoagulated and remains at risk for the condition being treated (DVT, PE, or stroke). I would notify the provider, anticipate a heparin rate increase, and recheck the aPTT in 6 hours per protocol. I would assess the patient for signs of new or worsening clotting and ensure they are on appropriate prophylactic measures.","Subtherapeutic anticoagulation management.","intermediate"),
  q("sq-ex4-49","professional_development","advocacy","A patient is refusing physical therapy because they are in too much pain.","How would you advocate for the patient while supporting the therapy plan?","I would first address the patient's pain—assess, medicate if appropriate, and time the PT session for when pain medication is most effective. I would communicate with the PT about the patient's pain levels and collaborate on a modified activity plan. I would educate the patient about the importance of mobility for recovery while validating their pain experience. Pain-free physical therapy improves participation and outcomes.","Pain management coordination to facilitate therapy participation.","beginner"),
  q("sq-ex4-50","interview_preparation","common_nursing_interview","The interviewer asks: 'What motivates you as a nurse?'","What drives you in your nursing career?","What motivates me is the knowledge that my actions directly impact someone's recovery, comfort, and quality of life. Every day brings the opportunity to learn something new and to make a meaningful difference. I am also motivated by the challenge—nursing requires constant critical thinking and adaptation. The relationships I build with patients and colleagues fuel my passion for this profession.","Authentic motivation beyond generic responses.","beginner"),
  q("sq-ex4-51","workplace_scenarios","handoff_communication","You receive a patient from another facility with incomplete transfer documentation.","How would you manage an incomplete interfacility transfer?","I would obtain what information I can from the transfer documentation and the patient/family. I would contact the sending facility directly to request missing information—medication lists, recent labs, operative notes, and allergy history. I would perform a thorough admission assessment to fill gaps. I would document what information was missing and from where, and escalate concerns about the transfer quality.","Proactive information gathering from multiple sources during incomplete transfers.","intermediate"),
  q("sq-ex4-52","clinical_transition","documentation_challenges","You need to document a conversation where a patient expressed suicidal ideation.","How would you document a patient's expression of suicidal thoughts?","I would document the exact words the patient used in quotes, the time and setting of the conversation, my assessment of their risk level, immediate safety interventions taken, who was notified (provider, psychiatry, charge nurse), the patient's current safety status, and the ongoing safety plan. I would use factual, non-judgmental language and document follow-up assessments. Thorough documentation protects the patient and is a legal record of appropriate interventions.","Thorough, factual documentation of psychiatric safety concerns.","advanced"),
  q("sq-ex4-53","professional_development","workplace_bullying","A colleague consistently undermines your decisions in front of patients.","How would you address a colleague who undermines your clinical decisions publicly?","I would address it privately first: 'When you question my clinical decisions in front of patients, it undermines their confidence in their care. If you disagree with my approach, I would appreciate discussing it privately or bringing it to the charge nurse.' If public undermining continued, I would document specific incidents and escalate to management, as this directly affects patient trust and care.","Private confrontation about public undermining.","advanced"),
  q("sq-ex4-54","career_navigation","career_advancement","You want to transition from hospital nursing to outpatient or clinic nursing.","How would you transition from inpatient to outpatient nursing?","I would research outpatient settings that interest me—primary care, specialty clinics, surgery centers, or urgent care. I would update my resume to highlight transferable skills: patient education, medication management, assessment skills, and care coordination. I would network with nurses in outpatient settings and apply for positions that offer training for the transition. I would be prepared for a different pace and scope of practice.","Strategic transition planning with transferable skill emphasis.","beginner"),
  q("sq-ex4-55","interview_preparation","clinical_judgment","A patient with a recent hip replacement develops sudden chest pain and tachycardia on post-op day 2.","What do you suspect and what are your priorities?","The combination of sudden chest pain and tachycardia after hip replacement raises high suspicion for pulmonary embolism from a DVT. I would keep the patient calm and positioned upright, apply supplemental oxygen, obtain vital signs and oxygen saturation, call the provider immediately, and prepare for a CT pulmonary angiography. I would establish IV access if not present and prepare for possible anticoagulation or thrombolytic therapy.","PE recognition in high-risk orthopedic patients.","advanced"),
  q("sq-ex4-56","workplace_scenarios","patient_safety","A patient is wearing a similar wristband color to another patient due to a labeling issue.","How would you address a potential patient identification issue?","I would immediately verify both patients' identities using two identifiers independent of the wristband. I would replace the confusing wristband with a correctly printed one. I would report the labeling issue to admitting and the charge nurse. I would perform a medication and treatment verification for both patients to ensure no cross-patient errors occurred. I would file an incident report about the identification concern.","Immediate verification and system correction for identification issues.","intermediate"),
  q("sq-ex4-57","clinical_transition","time_management","You are asked to precept a nursing student while managing your regular patient assignment.","How would you balance precepting with patient care responsibilities?","I would plan the day by identifying tasks the student can participate in or observe. I would involve the student in appropriate activities while maintaining oversight. I would set expectations at the start: 'I need to stay on schedule with my patients, so let us talk about what you can help with and when I need to work independently.' I would use each patient interaction as a teaching opportunity without sacrificing care quality.","Structured precepting within patient care demands.","intermediate"),
  q("sq-ex4-58","professional_development","patient_communication","A patient has been recently diagnosed with a chronic condition and is in denial.","How would you support a patient in denial about their diagnosis?","I would not force acceptance—denial is a normal initial response to bad news. I would provide factual information gently and consistently, be available for questions, and validate their emotions: 'This is a lot to process, and it is okay to take your time.' I would ensure they have educational materials for when they are ready and offer to connect them with support resources including counseling and peer support groups.","Respecting denial as a coping mechanism while providing gentle, consistent education.","intermediate"),
  q("sq-ex4-59","career_navigation","performance_evaluation","You receive an evaluation that is mostly positive but notes you need to improve team communication.","How would you improve team communication skills?","I would ask for specific examples of communication gaps so I can target my improvement. I would practice using SBAR for all clinical communications, give more detailed shift handoffs, participate more actively in team huddles, and proactively share information rather than waiting to be asked. I would ask trusted colleagues for real-time feedback on my communication. I would set a 3-month goal to demonstrate measurable improvement.","Specific communication improvement actions with measurable goals.","beginner"),
  q("sq-ex4-60","interview_preparation","behavioral","Tell me about a time you demonstrated cultural humility.","How have you practiced cultural humility in patient care?","I cared for a Muslim patient during Ramadan who was fasting despite being hospitalized. Rather than insisting she eat, I worked with the dietary team to provide nutritious meals at sunset and before dawn. I adjusted her medication schedule to accommodate her fasting and communicated with the physician about timing-sensitive medications. I learned that cultural humility means adapting our care to the patient's values rather than expecting the patient to adapt to ours.","Adapting care to patient's cultural practices rather than dismissing them.","intermediate"),
  q("sq-ex4-61","workplace_scenarios","delegation","You delegate ambulation to a CNA and the patient falls during the walk.","How would you manage a patient fall during a delegated task?","I would respond to the fall immediately—assess for injuries, take vital signs, and perform a neurological assessment. I would notify the provider. I would then review the circumstances with the CNA: was the patient properly assessed for ambulation safety, were assistive devices used, and was the patient's condition appropriate for the delegated task? I would file an incident report and ensure the fall prevention plan is updated.","Post-fall assessment with delegation review.","intermediate"),
  q("sq-ex4-62","clinical_transition","critical_thinking_drills","A patient's magnesium level is 1.2 mEq/L.","What is the clinical significance of hypomagnesemia?","A magnesium of 1.2 is below normal (1.5-2.5) and can cause muscle cramps, tremors, cardiac arrhythmias (especially torsades de pointes), and seizures. Hypomagnesemia often coexists with hypokalemia and hypocalcemia, making electrolyte management more complex. I would assess for cardiac symptoms, place the patient on telemetry, check potassium and calcium levels, and notify the provider for IV magnesium replacement.","Hypomagnesemia complications and associated electrolyte disturbances.","intermediate"),
  q("sq-ex4-63","professional_development","ethical_dilemmas","A patient tells you they plan to lie to their insurance company about the cause of their injury.","How would you respond to a patient telling you about planned insurance fraud?","I would not participate in or facilitate fraud. I would document the patient's actual reported history accurately. I would explain that my documentation must reflect what they tell me and what I observe. I would not lecture them about insurance fraud but would ensure my records are truthful. If they ask me to alter documentation to support a false claim, I would refuse and explain the legal implications.","Accurate documentation regardless of patient's stated intentions.","intermediate"),
  q("sq-ex4-64","career_navigation","job_offer_negotiation","You are negotiating a position at a hospital that does not have a new graduate residency program.","How would you negotiate orientation support without a formal residency program?","I would negotiate for extended orientation time, a dedicated preceptor, access to simulation training, and regular check-ins with a mentor. I would request: 'Without a formal residency program, I want to ensure I receive adequate support. Could we discuss extending my precepted orientation to 12-16 weeks with a consistent preceptor and monthly check-ins for the first year?' I would also ask about continuing education support.","Negotiating residency-equivalent support in non-residency settings.","intermediate"),
  q("sq-ex4-65","interview_preparation","star_examples","Tell me about a time you identified a learning opportunity and pursued it.","Describe your commitment to professional development.","After caring for several heart failure patients, I realized my knowledge of cardiac medications was not as deep as I wanted. Without being required to, I enrolled in an ACLS course, completed an online cardiac pharmacology module, and asked to be assigned to more cardiac patients during clinical. By graduation, my preceptor noted that my cardiac assessment skills were among the strongest in my cohort. I learned that identifying your own gaps is the first step to excellence.","Self-directed learning initiative with measurable competency improvement.","beginner"),
  q("sq-ex4-66","workplace_scenarios","patient_safety","A patient with a latex allergy is scheduled for a procedure that typically uses latex gloves.","How would you ensure safety for a patient with a latex allergy?","I would ensure the latex allergy is prominently documented and communicated to all team members. I would verify that non-latex gloves, catheters, and other supplies are available. I would place a latex allergy sign on the door and ensure the surgical or procedure team is aware. I would have emergency medications available in case of an allergic reaction. I would double-check all supplies entering the room.","Comprehensive latex allergy preparation and communication.","beginner"),
  q("sq-ex4-67","clinical_transition","documentation_challenges","You discover that your documentation was accidentally entered under another nurse's credentials.","How would you correct documentation entered under wrong credentials?","I would contact IT immediately to have the entry corrected or flagged. I would add a clarifying note indicating that the documentation was performed by me and entered incorrectly under another nurse's login. I would ensure both nurses are aware of the error. I would always verify I am logged in under my own credentials before documenting. This is a security and liability concern.","Immediate correction of credentialing errors in documentation.","intermediate"),
  q("sq-ex4-68","professional_development","advocacy","A patient's discharge is being rushed to free up a bed during a census surge.","How would you advocate against premature discharge during census pressure?","I would present my clinical assessment data: 'I understand we need the bed, but the patient still meets criteria for continued hospitalization—their vital signs are not stable, they cannot perform ADLs independently, and their family is not prepared for home care.' I would document my concerns, involve the case manager, and escalate to the medical director if I believe the discharge is unsafe.","Clinical data-driven advocacy against premature discharge.","intermediate"),
  q("sq-ex4-69","interview_preparation","clinical_judgment","A patient with renal failure has an elevated phosphorus level and declining calcium.","What would you anticipate for this electrolyte imbalance?","In renal failure, the kidneys cannot excrete phosphorus, leading to hyperphosphatemia. Elevated phosphorus binds calcium, causing hypocalcemia. I would anticipate orders for phosphorus binders to be taken with meals, calcium supplementation, dietary phosphorus restrictions, and possibly vitamin D supplementation. I would assess for symptoms of hypocalcemia: numbness, tingling, Chvostek's and Trousseau's signs, and cardiac arrhythmias.","Renal-related electrolyte imbalance management.","intermediate"),
  q("sq-ex4-70","career_navigation","career_advancement","You want to transition into nursing leadership but lack management experience.","How would you build a foundation for nursing leadership?","I would start with progressive leadership opportunities: serve as charge nurse, join hospital committees, participate in shared governance, and take on quality improvement project leadership. I would pursue an MSN in nursing leadership and seek mentorship from current nurse managers. I would develop business skills including budgeting, scheduling, and conflict resolution. I would demonstrate leadership through daily interactions, not just formal roles.","Progressive leadership development with formal education.","intermediate"),
  q("sq-ex4-71","interview_preparation","behavioral","Tell me about maintaining composure in an emotional situation.","How do you stay composed during emotionally intense moments?","When a young patient died unexpectedly during my ICU clinical rotation, I was deeply affected but needed to support the family and continue caring for my other patients. I focused on being present for the family, provided comfort care with dignity, and ensured my other patients were safe. After my shift, I processed my emotions through journaling and speaking with my preceptor. I learned that composure does not mean absence of emotion—it means managing emotions professionally.","Professional composure with healthy post-event processing.","advanced"),
  q("sq-ex4-72","workplace_scenarios","handoff_communication","You discover during handoff that a critical test result was not acted upon by the previous shift.","How would you handle discovering an unaddressed critical result during handoff?","I would immediately assess the patient and address the critical result. I would notify the physician if not already done. I would document the timeline: when the result was reported, when it was discovered during handoff, and what actions were taken. I would inform the charge nurse about the gap. I would file an incident report focused on system improvement rather than blame for the previous shift nurse.","Immediate patient action with system-focused incident reporting.","intermediate"),
  q("sq-ex4-73","clinical_transition","new_nurse_anxiety","You overheard a physician complaining about new nurses being slow and incompetent.","How would you handle overhearing negative physician comments about new nurses?","I would not internalize the comments as a reflection of my personal competence. Many physicians have worked with excellent new graduates. I would focus on demonstrating my competence through prepared, organized communication and quality patient care. If the comments were directed at me specifically and were disrespectful, I would address it professionally through appropriate channels.","Not internalizing generalized negativity while demonstrating competence.","beginner"),
  q("sq-ex4-74","professional_development","patient_communication","You need to teach a patient with low health literacy about their new diagnosis of hypertension.","How would you explain hypertension to a patient with limited health literacy?","I would use simple language: 'Your blood pressure is too high. Think of it like water pressure in a hose—too much pressure can damage the hose over time. We need to lower your blood pressure to protect your heart, kidneys, and brain.' I would use pictures and diagrams, demonstrate how to use a blood pressure monitor, create a simple medication schedule, and use teach-back: 'Can you tell me in your own words what we talked about?'","Plain language with analogies and teach-back verification.","beginner"),
  q("sq-ex4-75","career_navigation","probation_period","You are asked to take on responsibilities that seem beyond what other probationary nurses have.","How would you address expanded expectations during probation?","I would view it positively—additional responsibility could mean my manager trusts my abilities. However, I would clarify expectations: 'I am happy to take on this responsibility. Can you help me understand how it fits with my orientation goals and whether I should adjust my other priorities?' If the workload is genuinely unsafe, I would express that concern professionally and document it.","Balancing additional responsibility with appropriate boundary-setting.","intermediate"),
];
